use rxbyak::*;

/// Helper: assemble instructions and return the generated bytes.
fn assemble(f: impl FnOnce(&mut CodeAssembler) -> Result<()>) -> Vec<u8> {
    let mut asm = CodeAssembler::new(4096).unwrap();
    f(&mut asm).unwrap();
    asm.code().to_vec()
}

#[test]
fn test_nop() {
    let code = assemble(|a| a.nop());
    assert_eq!(code, [0x90]);
}

#[test]
fn test_ret() {
    let code = assemble(|a| a.ret());
    assert_eq!(code, [0xC3]);
}

#[test]
fn test_ret_imm() {
    let code = assemble(|a| a.ret_imm(8));
    assert_eq!(code, [0xC2, 0x08, 0x00]);
}

#[test]
fn test_int3() {
    let code = assemble(|a| a.int3());
    assert_eq!(code, [0xCC]);
}

