#[test]
fn test_label_forward_jmp() {
    let code = assemble(|a| {
        let label = a.create_label();
        a.jmp(&label, JmpType::Near)?;
        a.nop()?;
        a.nop()?;
        a.bind(&label)?;
        a.ret()
    });
    // jmp near (5 bytes) → E9 02 00 00 00
    // nop → 90
    // nop → 90
    // ret → C3
    assert_eq!(code, [0xE9, 0x02, 0x00, 0x00, 0x00, 0x90, 0x90, 0xC3]);
}

#[test]
fn test_label_backward_jmp() {
    let code = assemble(|a| {
        let label = a.create_label();
        a.bind(&label)?;
        a.nop()?;
        a.jmp(&label, JmpType::Near)
    });
    // nop → 90
    // jmp near → E9 FA FF FF FF (-6 = back to start, displacement = target - end_of_jmp)
    assert_eq!(code, [0x90, 0xE9, 0xFA, 0xFF, 0xFF, 0xFF]);
}

#[test]
fn test_jz_forward() {
    let code = assemble(|a| {
        let label = a.create_label();
        a.cmp(EAX, 0i32)?;
        a.jz(&label, JmpType::Near)?;
        a.nop()?;
        a.bind(&label)?;
        a.ret()
    });
    // cmp eax, 0  → 83 F8 00
    // jz near     → 0F 84 01 00 00 00
    // nop         → 90
    // ret         → C3
    assert_eq!(code, [0x83, 0xF8, 0x00, 0x0F, 0x84, 0x01, 0x00, 0x00, 0x00, 0x90, 0xC3]);
}

