#[test]
fn test_or_and_xor() {
    let code = assemble(|a| {
        a.or_(EAX, ECX)?;    // 09 C8
        a.and_(EAX, ECX)?;   // 21 C8
        a.xor_(EAX, ECX)     // 31 C8
    });
    assert_eq!(code, [0x09, 0xC8, 0x21, 0xC8, 0x31, 0xC8]);
}

