#[cfg(target_os = "windows")]
#[test]
fn test_jit_execution() {
    let mut asm = CodeAssembler::new(4096).unwrap();
    // Simple function: return 42
    // mov eax, 42
    // ret
    asm.mov(EAX, 42i32).unwrap();
    asm.ret().unwrap();
    asm.ready().unwrap();

    let f: extern "C" fn() -> i32 = unsafe { asm.get_code() };
    assert_eq!(f(), 42);
}
